select

from osg_job_application


        and student_name like concat('%', #{studentName}, '%')


        and company_name = #{companyName}


        and current_stage = #{currentStage}


        and lead_mentor_id = #{leadMentorId}


        and assign_status = #{assignStatus}


        and (
            student_name like concat('%', #{keyword}, '%')
            or company_name like concat('%', #{keyword}, '%')
            or position_name like concat('%', #{keyword}, '%')
        )


order by submitted_at desc, application_id desc

